import UIKit
import Alamofire
import SwiftyJSON

class Stock {
    var symbol: String
    var name: String
    var price: Double
    
    init(symbol: String, name: String, price: Double) {
        self.symbol = symbol
        self.name = name
        self.price = price
    }
}

class Portfolio {
    var stocks: [Stock] = []
    
    func add(stock: Stock) {
        stocks.append(stock)
    }
    
    func remove(stock: Stock) {
        if let index = stocks.firstIndex(where: { $0.symbol == stock.symbol }) {
            stocks.remove(at: index)
        }
    }
}

class TradingApp {
    var portfolio: Portfolio
    var apiEndpoint: String
    
    init(apiEndpoint: String) {
        self.apiEndpoint = apiEndpoint
        self.portfolio = Portfolio()
    }
    
    func executeTrade(symbol: String, quantity: Int) -> Bool {
        // Simulate API call to get current price
        let url = "\(apiEndpoint)/stock/\(symbol)"
        Alamofire.request(url).responseJSON { response in
            if let json = JSON(response.result.value) {
                let price = json["price"].doubleValue
                let stock = Stock(symbol: symbol, name: "", price: price)
                self.portfolio.add(stock: stock)
                print("Trade executed successfully")
                return true
            } else {
                print("Error executing trade")
                return false
            }
        }
        return false
    }
    
    func getPortfolio() -> [Stock] {
        return portfolio.stocks
    }
}

class ViewController: UIViewController {
    let tradingApp = TradingApp(apiEndpoint: "https://api.example.com")
    
    @IBOutlet weak var stockSymbolTextField: UITextField!
    @IBOutlet weak var quantityTextField: UITextField!
    @IBOutlet weak var executeTradeButton: UIButton!
    
    override func viewDidLoad() {
        super.viewDidLoad()
        // Do any additional setup after loading the view.
    }
    
    @IBAction func executeTradeButtonTapped(_ sender: UIButton) {
        if let symbol = stockSymbolTextField.text, let quantityString = quantityTextField.text, let quantity = Int(quantityString) {
            tradingApp.executeTrade(symbol: symbol, quantity: quantity)
            print("Trade executed")
        } else {
            print("Invalid input")
        }
    }
}